function a(){const o=document.getElementById("pais"),t=document.getElementById("region");fetch("/api/obtenerPaises").then(e=>{if(!e.ok)throw new Error("error al cargar los paises");return e.json()}).then(e=>{for(const r of e){const n=document.createElement("option");n.value=r.codigo,n.textContent=r.nombre,o.appendChild(n)}}),t.disabled=!0,o.addEventListener("change",()=>{i(o.value)})}function i(o){const t=document.getElementById("region");return fetch(`/api/obtenerRegiones?pais=${o}`).then(e=>{if(!e.ok)throw new Error("error al cargar las provincias");return e.json()}).then(e=>{t.innerHTML="<option disabled selected>Elige tu region</option>";for(const r of e){const n=document.createElement("option");n.value=r.id,n.textContent=r.nombre,t.appendChild(n)}t.disabled=!1}).catch(e=>console.log(e))}export{i as o,a as s};
